dsl: snowmountain.spec/v1
kind: component
metadata:
  id: control-plane.capabilities
  title: Managed Agents 中台能力全景图
  status: partial
  owners: [control-plane]
  tags: [ui, api, parity]
intent:
  summary: 用可审查的高密度投影向人类展示已验证、部分实现和规划中的平台能力。
  outcomes:
    - 进度来自结构化状态与验证证据，不要求人类阅读大量 Markdown 后自行推测。
  nonGoals:
    - 因为存在页面或路由就声称已经完整对齐火山方舟。
knowledge:
  - docs/notes/volcengine-managed-agents-reverse-engineering.md
specRefs: [session.lifecycle, sandbox.boundary, agent.runtime, memory.lifecycle, market.integration, tool.resolution, credential.binding, platform.boundary]
contract:
  role: human-and-api-control-plane
  runtime: fastify-react-sqlite
  adapters: []
  ports:
    - { id: human-console, direction: in, protocol: https-react }
    - { id: control-api, direction: in, protocol: authenticated-rest }
    - { id: data-api, direction: in, protocol: bearer-rest }
  features:
    - { id: tenancy, label: 管理员/普通用户角色与 tenantId 数据隔离, status: verified, evidence: apps/api/test/api.test.ts }
    - { id: model-catalog, label: 管理员模型 Endpoint 与普通用户模型选择器, status: verified, evidence: apps/api/test/api.test.ts }
    - { id: agents, label: Agent 不可变版本、Latest 与当前版本切换, status: verified, evidence: apps/api/test/api.test.ts }
    - { id: sessions, label: "Session、持久队列、对话投影与事件回放", status: verified, evidence: apps/api/test/api.test.ts }
    - { id: environments, label: Environment 依赖与普通变量, status: implemented, evidence: apps/web/src/pages/Resources.tsx }
    - { id: vault, label: Credential Vault、显式绑定与 OAuth 刷新, status: verified, evidence: apps/api/test/mcp.test.ts }
    - { id: memory, label: 显式长期 Memory Store, status: partial, evidence: spec/contracts/memory-lifecycle.yaml }
    - { id: market, label: Git-first Market 集成, status: implemented, evidence: spec/contracts/market-integration.yaml }
    - { id: sandbox, label: 可替换的隔离执行后端, status: verified, evidence: apps/worker/test/worker.test.ts }
    - { id: runtime, label: 生产级 Agent SDK Runtime, status: partial, evidence: spec/contracts/agent-runtime.yaml }
    - { id: observability, label: "审计、事件与 Prometheus 指标", status: implemented, evidence: apps/api/src/app.ts }
  limitations:
    - UI 对齐不代表已经复刻火山方舟未公开的服务端行为。
    - Runtime SDK 选型、Memory 自动抽取和强于 runc 的隔离仍是明确的开放契约。
implementation:
  code:
    - apps/api/src/app.ts
    - apps/web/src/App.tsx
  notes:
    - 规范查看器是开发者投影，不是 Managed Agents 业务模块。
verification:
  tests:
    - apps/api/test/api.test.ts
    - apps/worker/test/worker.test.ts
  assertions:
    - { id: honest-status, assertion: 部分实现、已实现和已验证能力必须在界面中清楚区分。 }
    - { id: viewer-separation, assertion: Managed Agents 业务侧栏不得包含 SDD 或项目文档栏目。 }

dsl: snowmountain.spec/v1
kind: capability-policy
metadata:
  id: credential.binding
  title: Vault Credential 显式绑定与秘密解析边界
  status: verified
  owners: [runtime-security]
  tags: [vault, credential, agent-version, environment]
intent:
  summary: Vault 是租户级可发现资源池，但任何秘密使用都必须存在可审计的 MCP/Skill 引用；平台模型秘密属于管理员控制面。
  outcomes:
    - Vault 是当前 tenant 的 Credential 加密容器，不直接绑定 Environment 或 Session。
    - 模型 Provider Credential 由管理员 Model Endpoint 托管，普通用户只选择模型目录项。
    - MCP Credential 由 Agent McpServerBinding.credentialId 显式选择。
    - Environment 不接受 secret 变量，Sandbox 永远不接收 Vault 明文。
  nonGoals:
    - 把 Vault 或平台模型 Endpoint 的秘密注入模型上下文或 Sandbox 环境变量。
knowledge:
  - docs/notes/runtime-sandbox-memory-decisions.md
specRefs: [sandbox.boundary, agent.runtime, session.lifecycle]
contract:
  subjects:
    - { id: platform-admin, label: 平台模型与 Runtime 管理员 }
    - { id: agent-version, label: 固定能力引用的 Agent Version }
    - { id: credential-proxy, label: 控制面 Credential 代理 }
    - { id: session, label: Session 运行记录 }
    - { id: environment, label: 可复现依赖与普通变量模板 }
    - { id: sandbox, label: 不可信 Tool 执行容器 }
  resources:
    - { id: model-endpoint-secret, label: 平台模型 Endpoint 密钥 }
    - { id: credential-reference, label: 非秘密 Credential ID }
    - { id: vault-secret, label: Vault 加密秘密明文 }
    - { id: environment-variable, label: Environment 普通变量 }
  grants:
    - { subject: platform-admin, resource: model-endpoint-secret, access: write }
    - { subject: agent-version, resource: credential-reference, access: read }
    - { subject: agent-version, resource: vault-secret, access: none }
    - { subject: credential-proxy, resource: vault-secret, access: read }
    - { subject: session, resource: credential-reference, access: none }
    - { subject: session, resource: vault-secret, access: none }
    - { subject: environment, resource: environment-variable, access: write }
    - { subject: environment, resource: vault-secret, access: none }
    - { subject: sandbox, resource: environment-variable, access: read }
    - { subject: sandbox, resource: vault-secret, access: none }
    - { subject: sandbox, resource: model-endpoint-secret, access: none }
  constraints:
    - id: reference-is-not-secret
      type: mutually-exclusive
      resources: [credential-reference, vault-secret]
      assertion: 除控制面 Credential 代理外，任何主体都不能同时持有引用和秘密；代理本身不进入模型或 Sandbox。
implementation:
  code:
    - apps/api/src/vault.ts
    - apps/api/src/mcp.ts
    - apps/api/src/harness.ts
    - apps/api/src/app.ts
    - apps/api/src/sandbox.ts
    - apps/web/src/pages/Resources.tsx
    - apps/web/src/pages/Agents.tsx
  notes:
    - 历史 MODEL_API_KEY 与 Agent.model.credentialId 仅作兼容路径；普通用户界面只选择管理员发布的 Model Endpoint。
verification:
  tests:
    - apps/api/test/api.test.ts
    - apps/api/test/mcp.test.ts
    - apps/api/test/sandbox.test.ts
  assertions:
    - { id: explicit-reference, assertion: 删除被 Agent 模型或 MCP binding 引用的 Credential 会因依赖边被拒绝。 }
    - { id: no-environment-secret, assertion: API 拒绝 secret Environment variable，Sandbox 也会防御性过滤旧数据。 }
    - { id: tenant-vault, assertion: 普通用户不能列出、读取或删除其他 tenant 的 Vault/Credential。 }

dsl: snowmountain.spec/v1
kind: state-machine
metadata:
  id: session.lifecycle
  title: Managed Session 持久生命周期
  status: verified
  owners: [control-plane]
  tags: [session, queue, recovery]
intent:
  summary: Session 是持久状态与证据，不等于一次模型请求或一个 Sandbox Container 的生命周期。
  outcomes:
    - 每个 Session 内 Interaction 串行执行，持久队列跨进程重启恢复。
    - 被中断的副作用不会在重启后静默重放。
    - Session 只保存 agentId；每次 Interaction 解析 Agent 当前版本，历史实际版本写入事件。
  nonGoals:
    - 在没有显式重试的情况下重建被中断的模型或 Tool Call。
knowledge:
  - docs/notes/anthropic-managed-agents.md
  - docs/notes/fable5-sdd-dialogue-reading-notes.md
specRefs: [sandbox.boundary, agent.runtime]
contract:
  initial: idle
  states:
    - { id: idle, label: 空闲 }
    - { id: queued, label: 已排队 }
    - { id: running, label: 运行中 }
    - { id: failed, label: 失败 }
    - { id: stopped, label: 已停止, terminal: true }
  transitions:
    - { from: idle, event: interaction_submitted, to: queued, effect: persist_job_and_status_event }
    - { from: failed, event: explicit_retry, to: queued, effect: persist_new_job }
    - { from: queued, event: worker_claimed, to: running, effect: append_running_event }
    - { from: queued, event: user_stop, to: stopped, effect: cancel_queued_job }
    - { from: running, event: turn_completed, to: idle, effect: append_end_turn }
    - { from: running, event: execution_failed, to: failed, effect: persist_error }
    - { from: running, event: user_stop, to: stopped, effect: abort_execution }
  invariants:
    - { id: one-active-job, assertion: 同一 Session 同时最多执行一个 Interaction。 }
    - { id: append-only-evidence, assertion: 每次状态转换都必须写入只追加的 Session 事件。 }
    - { id: no-silent-replay, assertion: 重启时仍在运行的 Job 必须转为失败，不得自动重放。 }
    - { id: agent-reference-only, assertion: Session 不固定 Agent Version；当前版本由 Agent 资源统一选择。 }
implementation:
  code:
    - apps/api/src/queue.ts
    - apps/api/src/db.ts
    - apps/api/src/harness.ts
  notes:
    - 当前持久队列与事件存储由 SQLite WAL 实现。
    - 数据模型仍兼容历史 waiting_approval 事件；当前调试模式自动放行 approval policy，不进入该状态。
verification:
  tests:
    - apps/api/test/api.test.ts
  assertions:
    - { id: queue-restart, assertion: 启动前已持久化的排队 Interaction 会在重启后继续处理。 }
    - { id: workspace-restart, assertion: API 进程重启后，Session 仍能读取同一 Workspace 文件。 }
